class Memento:
    def __init__(self, s):
        self._s = s
    def get(self):
        return self._s

class Originator:
    def __init__(self):
        self.state = None
    def save(self):
        return Memento(self.state)
    def restore(self, m):
        self.state = m.get()

o = Originator()
o.state = 'A'
m = o.save()
o.state = 'B'
o.restore(m)
print(o.state)
